pipeline.evaluate:
(() => {
  const items = [];
  document.querySelectorAll('[data-testid="card-headline"]').forEach(el => {
    const link = el.closest('a');
    if (link) {
      items.push({
        title: el.textContent.trim(),
        url: link.href.startsWith('http') ? link.href : 'https://www.bbc.com' + link.href
      });
    }
  });
  return items;
})()
